mapper.update:
UPDATE visit_appointment
SET status = 'CANCELED'
WHERE id = #{appointmentId}
  AND elder_id = #{elderId}
  AND status IN ('PENDING', 'APPROVED')

mapper.select:
SELECT *
FROM visit_appointment
WHERE elder_id = #{elderId}

    AND status = #{status}


    AND visit_time >= #{from}


    AND visit_time <= #{to}

ORDER BY visit_time ASC
